        const rawPhone = String(row[4] || '').trim();
        const rawPassword = String(row[5] || '').trim();

        if (!rawName && !rawCode && !rawClass && !rawRoom && !rawPhone) continue;

        let errors = [];
        let studentClass = '';
        let studentRoom = '';

        if (!rawName) {
            errors.push('กรุณาระบุชื่อ-นามสกุล');
        }
        if (!rawCode) {
            errors.push('กรุณาระบุรหัสประจำตัว');
        }

        if (!rawClass) {
            errors.push('กรุณาระบุระดับชั้น');
        } else {
            if (rawClass.includes('1') || rawClass.includes('m1') || rawClass.includes('ม.1')) {
                studentClass = 'm1';
            } else if (rawClass.includes('2') || rawClass.includes('m2') || rawClass.includes('ม.2')) {
                studentClass = 'm2';
            } else if (rawClass.includes('3') || rawClass.includes('m3') || rawClass.includes('ม.3')) {
                studentClass = 'm3';
            } else {
                errors.push('ระดับชั้นไม่ถูกต้อง (ระบุ m1, m2, หรือ m3)');
            }
        }

        if (!rawRoom) {
            errors.push('กรุณาระบุห้องเรียน');
        } else {
            const matchNum = rawRoom.match(/[1-3]/);
            if (matchNum) {
                studentRoom = matchNum[0];
            } else {
                errors.push('ห้องเรียนไม่ถูกต้อง (ระบุ 1, 2, หรือ 3)');
            }
        }

        let isDuplicate = false;
        if (rawName && studentRoom) {
            const formattedRoom = `ม.${studentClass === 'm3' ? '3' : studentClass === 'm2' ? '2' : '1'}/${studentRoom}`;
            const dup = leaderboardDatabase.find(s => s.name === rawName && s.room === formattedRoom);
            if (dup) {
                errors.push('ชื่อนักเรียนซ้ำในห้องนี้แล้ว');
            }
        }

        // Gen simple 4-digit PIN if password is empty
        const studentPassword = rawPassword || String(Math.floor(1000 + Math.random() * 9000));

        const isValid = errors.length === 0;
        if (isValid) {
            validCount++;
            window.tempParsedStudents.push({
                name: rawName,
                code: rawCode,
                class: studentClass,
                room: `ม.${studentClass === 'm3' ? '3' : studentClass === 'm2' ? '2' : '1'}/${studentRoom}`,
                phone: rawPhone || null,
                password: studentPassword
            });
        } else {
            invalidCount++;
        }

        const tr = document.createElement('tr');
        tr.style.borderBottom = '1px solid var(--border)';
        tr.style.background = isValid ? 'var(--white)' : 'rgba(239, 68, 68, 0.02)';

        const statusBadge = isValid 
            ? '<span style="background: var(--success-bg); color: var(--success-text); padding: 2px 8px; border-radius: 12px; font-size: 0.72rem; font-weight: 600;">ผ่าน</span>' 
            : `<span style="background: var(--danger-bg); color: var(--danger-text); padding: 2px 8px; border-radius: 12px; font-size: 0.72rem; font-weight: 600; display: inline-block; cursor: help;" title="${errors.join(', ')}">ไม่ผ่าน (${errors.length})</span>`;

        tr.innerHTML = `
            <td style="padding: 8px 12px; color: var(--text-muted);">${i}</td>
            <td style="padding: 8px 12px; font-weight: 600; color: var(--text-main);">${rawName || '-'}</td>
            <td style="padding: 8px 12px; font-family: monospace; color: var(--text-main);">${rawCode || '-'}</td>
            <td style="padding: 8px 12px; color: var(--text-main);">${studentClass ? (studentClass === 'm3' ? 'ม.3' : studentClass === 'm2' ? 'ม.2' : 'ม.1') : (rawClass || '-')}</td>
            <td style="padding: 8px 12px; color: var(--text-main);">${studentRoom ? 'ห้อง ' + studentRoom : (rawRoom || '-')}</td>
            <td style="padding: 8px 12px; color: var(--text-main);">${rawPhone || '-'}</td>
            <td style="padding: 8px 12px; font-family: monospace; color: #10b981; font-weight: 600;">${studentPassword}</td>
            <td style="padding: 8px 12px;">${statusBadge}</td>
        `;
        tbody.appendChild(tr);
    }

    countEl.textContent = rows.length - 1;
    previewSection.style.display = 'flex';

    if (validCount > 0) {
        badge.style.background = 'var(--success-bg)';
        badge.style.color = 'var(--success-text)';
        badge.textContent = `ตรวจสอบสำเร็จ (ผ่าน ${validCount} / ไม่ผ่าน ${invalidCount})`;

        btnConfirm.disabled = false;
        btnConfirm.style.opacity = '1';
        btnConfirm.style.cursor = 'pointer';
    } else {
        badge.style.background = 'var(--danger-bg)';
        badge.style.color = 'var(--danger-text)';
        badge.textContent = 'ไม่พบข้อมูลที่ผ่านเกณฑ์การตรวจสอบ';

        btnConfirm.disabled = true;
        btnConfirm.style.opacity = '0.5';
        btnConfirm.style.cursor = 'not-allowed';
    }
}

